// ===== v7.2: Authenticated calls moved to HTTP Request nodes =====
// This Code node only does:
// 1. Extract channels from Notion HTTP response → fetch public YouTube RSS
// 2. Read IG/X results from upstream HTTP Request nodes
// 3. Combine all into feedText

function extractAtomEntries(xml, sourceName, maxItems = 5, hoursAgo = 72) {
  if (!xml || typeof xml !== 'string') return [];
  const entries = [];
  const cutoff = new Date(Date.now() - hoursAgo * 60 * 60 * 1000);
  const regex = /<entry>(.*?)<\/entry>/gs;
  let match;
  while ((match = regex.exec(xml)) !== null && entries.length < maxItems) {
    const titleMatch = match[1].match(/<title>(.*?)<\/title>/);
    const pubMatch = match[1].match(/<published>(.*?)<\/published>/);
    const descMatch = match[1].match(/<media:description>(.*?)<\/media:description>/s);
    const linkMatch = match[1].match(/<link[^>]+href="([^"]+)"/);
    if (titleMatch) {
      const pubDate = pubMatch ? new Date(pubMatch[1]) : new Date(0);
      if (pubDate >= cutoff) {
        entries.push({
          source: sourceName,
          title: titleMatch[1].trim(),
          description: descMatch ? descMatch[1].replace(/<[^>]*>/g, '').substring(0, 200).trim() : '',
          published: pubMatch ? pubMatch[1] : '',
          link: linkMatch ? linkMatch[1] : ''
        });
      }
    }
  }
  return entries;
}

// ===== 1. Notion Channels → YouTube RSS (public, no auth needed) =====
let allYtEntries = [];
try {
  const notionData = $('Notion Channels').first().json;
  const results = notionData.results || [];
  const channels = [];
  for (const page of results) {
    const props = page.properties;
    const type = props['類型']?.select?.name || '';
    const name = props['Name']?.title?.[0]?.plain_text || '';
    if (type === '📺 頻道') {
      const channelId = props['Channel ID']?.rich_text?.[0]?.plain_text || '';
      if (channelId && name) channels.push({ name, channelId });
    }
  }
  for (const ch of channels) {
    try {
      const url = `https://www.youtube.com/feeds/videos.xml?channel_id=${ch.channelId}`;
      const res = await this.helpers.httpRequest({ method: 'GET', url, timeout: 10000 });
      allYtEntries.push(...extractAtomEntries(String(res), ch.name));
    } catch (e) {}
  }
} catch (e) {}

// ===== 2. Get IG posts from HTTP Request node (fullResponse: {body: [...]}) =====
let igPosts = [];
try {
  const igData = $('Apify IG').first().json;
  const raw = igData.body || igData;
  if (Array.isArray(raw)) igPosts = raw;
} catch (e) {}

// ===== 3. Get X tweets from HTTP Request node (fullResponse: {body: [...]}) =====
let xTweets = [];
try {
  const xData = $('Apify X').first().json;
  const raw = xData.body || xData;
  if (Array.isArray(raw)) {
    xTweets = raw.filter(t => t.text && !t.demo && !t.noResults);
  }
} catch (e) {}

// ===== 4. Sort tweets by engagement =====
xTweets.sort((a, b) => {
  const scoreA = (a.likeCount || 0) + (a.retweetCount || 0) * 2;
  const scoreB = (b.likeCount || 0) + (b.retweetCount || 0) * 2;
  return scoreB - scoreA;
});

// ===== 5. Combine all into feedText =====
let feedText = '';

if (xTweets.length > 0) {
  feedText += '\n\n--- 🐦 X/Twitter 實際應用分享 ---\n';
  for (const tweet of xTweets.slice(0, 40)) {
    const username = tweet.author?.userName || '?';
    const text = (tweet.text || '').substring(0, 300);
    const likes = tweet.likeCount || 0;
    const retweets = tweet.retweetCount || 0;
    const url = tweet.url || '';
    feedText += `- [@${username}] ${text}\n  ❤️ ${likes} 🔄 ${retweets}\n`;
    if (url) feedText += `  🔗 ${url}\n`;
  }
}

if (allYtEntries.length > 0) {
  feedText += '\n\n--- 🎬 YouTube 頻道更新（72h） ---\n';
  for (const entry of allYtEntries) {
    feedText += `- [${entry.source}] ${entry.title}\n`;
    if (entry.description) feedText += `  ${entry.description}\n`;
    if (entry.link) feedText += `  🔗 ${entry.link}\n`;
  }
}

if (igPosts.length > 0) {
  feedText += '\n\n--- 📸 Instagram ---\n';
  for (const post of igPosts.slice(0, 10)) {
    const owner = post.ownerUsername || '?';
    const caption = (post.caption || '').substring(0, 300);
    const likes = post.likesCount || 0;
    const url = post.url || (post.shortCode ? `https://www.instagram.com/p/${post.shortCode}/` : '');
    feedText += `- [@${owner}] ${caption}\n  ❤️ ${likes}\n`;
    if (url) feedText += `  🔗 ${url}\n`;
  }
}

const ytCount = allYtEntries.length;
const igCount = igPosts.length;
const xCount = xTweets.length;

if (ytCount === 0 && igCount === 0 && xCount === 0) {
  feedText = '（今日所有來源都抓取失敗，請手動檢查設定）';
}

return [{ json: { feedText, ytCount, igCount, xCount, totalCount: ytCount + igCount + xCount } }];

// 格式化摘要 v7.2 + 分段（避免 Telegram 4096 字元限制）
const content = $input.first().json;
let text = '';

if (content.content && content.content[0] && content.content[0].text) {
  text = content.content[0].text;
} else {
  text = '⚠️ Claude API 回覆異常，請手動檢查 workflow。';
}

// 移除 Markdown 格式，保留 HTML
text = text.replace(/\*\*/g, '');
text = text.replace(/\*/g, '');

// 加上日期和簽名
const now = new Date();
const taipeiOffset = 8 * 60;
const taipeiTime = new Date(now.getTime() + (taipeiOffset + now.getTimezoneOffset()) * 60000);
const today = taipeiTime.toISOString().split('T')[0];
const hour = taipeiTime.getHours();
const period = hour < 14 ? '☀️ 早安' : '🌙 晚安';

// 加上抓取統計
const fetchNode = $('Combine All Sources').first().json;
const stats = `📊 來源：X ${fetchNode.xCount || 0} 則 / YT ${fetchNode.ytCount || 0} 支 / IG ${fetchNode.igCount || 0} 則`;

text += `\n\n---\n📅 ${today} ${period} | ${stats}\n🤖 Ray AI 管家 Jarvis v7.2`;

// 分段處理（Telegram 單則訊息上限 4096 字元）
const MAX_LEN = 4000;
if (text.length <= MAX_LEN) {
  return [{ json: { digest: text, parseMode: 'HTML' } }];
}

const sections = text.split('\n\n');
const messages = [];
let current = '';
for (const section of sections) {
  if ((current + '\n\n' + section).length > MAX_LEN && current.length > 0) {
    messages.push(current.trim());
    current = section;
  } else {
    current = current ? current + '\n\n' + section : section;
  }
}
if (current.trim()) messages.push(current.trim());

return messages.map((msg) => ({ json: { digest: msg, parseMode: 'HTML' } }));
